// ProductList.js - Version optimisée
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { FlatList, ActivityIndicator, View, Text } from 'react-native';

const ProductList = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('https://api.example.com/products')
      .then(res => res.json())
      .then(data => {
        setProducts(data);
        setLoading(false);
      });
  }, []);

  // useCallback pour stabiliser la fonction entre les rendus
  const handleLike = useCallback((productId) => {
    setProducts(prevProducts => 
      prevProducts.map(p => 
        p.id === productId ? { ...p, liked: !p.liked } : p
      )
    );
  }, []);

  // useMemo pour éviter de recréer l'item separator à chaque rendu
  const ItemSeparator = useMemo(() => () => (
    <View style={{ height: 1, backgroundColor: '#ccc' }} />
  ), []);

  const renderItem = useCallback(({ item }) => (
    <ProductCard 
      product={item}
      onLike={handleLike}
    />
  ), [handleLike]);

  const keyExtractor = useCallback((item) => item.id.toString(), []);

  if (loading) {
    return <ActivityIndicator size="large" style={{ flex: 1 }} />;
  }

  return (
    <FlatList
      data={products}
      renderItem={renderItem}
      keyExtractor={keyExtractor}
      ItemSeparatorComponent={ItemSeparator}
      initialNumToRender={10}
      maxToRenderPerBatch={10}
      windowSize={5}
      removeClippedSubviews={true}
      getItemLayout={(data, index) => ({
        length: 120, // hauteur estimée de chaque élément
        offset: 120 * index,
        index,
      })}
    />
  );
};

// ProductCard.js - Avec React.memo
import React, { memo } from 'react';
import { View, Text, Image, TouchableOpacity, StyleSheet } from 'react-native';

const ProductCard = memo(({ product, onLike }) => {
  // useState est correct ici car c'est un état local indépendant
  const [localCount, setLocalCount] = useState(0);

  // useCallback pour les handlers internes
  const handleLocalPress = useCallback(() => {
    setLocalCount(prev => prev + 1);
  }, []);

  const handleLikePress = useCallback(() => {
    onLike(product.id);
  }, [onLike, product.id]);

  return (
    <View style={styles.card}>
      <Image source={{ uri: product.image }} style={styles.image} />
      <Text style={styles.name}>{product.name}</Text>
      <Text style={styles.price}>{product.price} FCFA</Text>
      <TouchableOpacity onPress={handleLikePress} style={styles.button}>
        <Text>{product.liked ? '❤️' : '🤍'} Like</Text>
      </TouchableOpacity>
      <TouchableOpacity onPress={handleLocalPress} style={styles.button}>
        <Text>Compteur local: {localCount}</Text>
      </TouchableOpacity>
    </View>
  );
}, (prevProps, nextProps) => {
  // Comparaison personnalisée pour éviter les re-rendus inutiles
  return prevProps.product.id === nextProps.product.id &&
         prevProps.product.liked === nextProps.product.liked &&
         prevProps.product.price === nextProps.product.price &&
         prevProps.product.name === nextProps.product.name;
});

const styles = StyleSheet.create({
  card: { margin: 10, padding: 10, borderWidth: 1, borderRadius: 8 },
  image: { width: 100, height: 100 },
  name: { fontSize: 16, fontWeight: 'bold' },
  price: { color: 'green', marginVertical: 5 },
  button: { backgroundColor: '#eee', padding: 8, borderRadius: 4, marginTop: 5 },
});

export default ProductList;
