// useLocalStorage.test.js
import { renderHook, act, waitFor } from '@testing-library/react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useLocalStorage } from './useLocalStorage';

// Mock d'AsyncStorage
jest.mock('@react-native-async-storage/async-storage', () => ({
  getItem: jest.fn(),
  setItem: jest.fn(),
}));

describe('useLocalStorage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  test('(a) devrait charger la valeur initiale depuis AsyncStorage', async () => {
    // Arrange
    const mockData = { name: 'Jean', age: 25 };
    AsyncStorage.getItem.mockResolvedValue(JSON.stringify(mockData));

    // Act
    const { result } = renderHook(() => useLocalStorage('user', { name: 'default' }));

    // Assert - vérifie l'état de chargement initial
    expect(result.current.loading).toBe(true);
    expect(AsyncStorage.getItem).toHaveBeenCalledWith('user');

    // Attend que le chargement soit terminé
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });

    // Vérifie que la valeur chargée est correcte
    expect(result.current.storedValue).toEqual(mockData);
  });

  test('(a bis) devrait utiliser la valeur initiale si AsyncStorage est vide', async () => {
    // Arrange
    const initialValue = { name: 'default', age: 0 };
    AsyncStorage.getItem.mockResolvedValue(null);

    // Act
    const { result } = renderHook(() => useLocalStorage('emptyKey', initialValue));

    // Assert
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });
    expect(result.current.storedValue).toEqual(initialValue);
  });

  test('(b) devrait sauvegarder une nouvelle valeur dans AsyncStorage', async () => {
    // Arrange
    AsyncStorage.getItem.mockResolvedValue(null);
    const { result } = renderHook(() => useLocalStorage('settings', { theme: 'light' }));

    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });

    // Act
    const newSettings = { theme: 'dark', notifications: true };
    await act(async () => {
      await result.current.setValue(newSettings);
    });

    // Assert
    expect(result.current.storedValue).toEqual(newSettings);
    expect(AsyncStorage.setItem).toHaveBeenCalledWith(
      'settings',
      JSON.stringify(newSettings)
    );
  });

  test('(c) devrait mettre à jour une valeur existante avec une fonction', async () => {
    // Arrange
    const existingData = { count: 5 };
    AsyncStorage.getItem.mockResolvedValue(JSON.stringify(existingData));
    const { result } = renderHook(() => useLocalStorage('counter', { count: 0 }));

    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });

    // Act - mise à jour fonctionnelle (comme setCount(prev => prev + 1))
    await act(async () => {
      await result.current.setValue(prev => ({ count: prev.count + 1 }));
    });

    // Assert
    expect(result.current.storedValue).toEqual({ count: 6 });
    expect(AsyncStorage.setItem).toHaveBeenCalledWith(
      'counter',
      JSON.stringify({ count: 6 })
    );
  });

  test('(c bis) devrait gérer les erreurs AsyncStorage sans crasher', async () => {
    // Arrange
    const consoleSpy = jest.spyOn(console, 'error').mockImplementation();
    AsyncStorage.getItem.mockRejectedValue(new Error('Network error'));

    // Act
    const { result } = renderHook(() => useLocalStorage('errorKey', 'default'));

    // Assert
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });
    expect(consoleSpy).toHaveBeenCalled();
    expect(result.current.storedValue).toBe('default'); // Valeur par défaut conservée

    consoleSpy.mockRestore();
  });
});
